  9→const DOOR_INSERT_THICKNESS_MIN = 35;
 10→const DOOR_INSERT_THICKNESS_MAX = 70;
 11→const WINDOW_INSERT_THICKNESS_MIN = 45;
 12→const WINDOW_INSERT_THICKNESS_MAX = 90;
 13→
 14→function createBoundsFromPoints(points, baseElevation, topElevation) {
 15→  if (!points?.length) {
 16→    return {
 17→      minX: 0,
 18→      maxX: 0,
 19→      minY: 0,
 20→      maxY: 0,
 21→      minElevation: baseElevation,
 22→      maxElevation: topElevation,
 23→    };
 24→  }
 25→
 26→  return {
 27→    minX: Math.min(...points.map((point) => point.x)),
 28→    maxX: Math.max(...points.map((point) => point.x)),
 29→    minY: Math.min(...points.map((point) => point.y)),
 30→    maxY: Math.max(...points.map((point) => point.y)),
 31→    minElevation: baseElevation,
 32→    maxElevation: topElevation,
 33→  };
 34→}
 35→
 36→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 37→  const topElevation = baseElevation + height;
 38→  return {
 39→    id,
 40→    kind,
 41→    geometry: 'prism',
 42→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 43→    baseElevation,
 44→    height,
 45→    materialKey: metadata.materialKey || kind,
 46→    metadata,
 47→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 48→  };
 49→}
 50→
 51→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 52→  const outline = wallOutline({
 53→    start: { x: startPoint.x, y: startPoint.y },
 54→    end: { x: endPoint.x, y: endPoint.y },
 55→    thickness: width,
 56→  });
 57→  const direction = wallDirection({
 58→    start: { x: startPoint.x, y: startPoint.y },
 59→    end: { x: endPoint.x, y: endPoint.y },
 60→  });
 61→  const topElevation = baseElevation + height;
 62→
 63→  return {
 64→    id,
 65→    kind,
 66→    geometry: 'box',
 67→    center: {
 68→      x: (startPoint.x + endPoint.x) / 2,
 69→      y: (startPoint.y + endPoint.y) / 2,
 70→    },
 71→    size: {
 72→      x: wallLength({ start: startPoint, end: endPoint }),
 73→      y: height,
 74→      z: width,
 75→    },
 76→    rotation: Math.atan2(direction.y, direction.x),
 77→    baseElevation,
 78→    materialKey: metadata.materialKey || kind,
 79→    metadata,
 80→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 81→  };
 82→}
 83→
 84→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 85→  const halfX = size.x / 2;
 86→  const halfZ = size.z / 2;
 87→  const cos = Math.cos(rotation);
 88→  const sin = Math.sin(rotation);
 89→  const corners = [
 90→    { x: -halfX, y: -halfZ },
 91→    { x: halfX, y: -halfZ },
 92→    { x: halfX, y: halfZ },
 93→    { x: -halfX, y: halfZ },
 94→  ].map((point) => ({
 95→    x: center.x + (point.x * cos - point.y * sin),
 96→    y: center.y + (point.x * sin + point.y * cos),
 97→  }));
 98→
 99→  return {
100→    id,
101→    kind,
102→    geometry: 'box',
103→    center: { x: center.x, y: center.y },
104→    size,
105→    rotation,
106→    baseElevation,
107→    materialKey: metadata.materialKey || kind,
108→    metadata,
109→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
110→  };
111→}
