141→function buildWallObjects(wallContexts) {
142→  return wallContexts.flatMap((context) => (
143→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
144→      segment.id,
145→      'wall',
146→      segment.startPoint,
147→      segment.endPoint,
148→      segment.thickness,
149→      segment.baseElevation,
150→      segment.topElevation - segment.baseElevation,
151→      {
152→        sourceId: segment.wallId,
153→        floorId: segment.floorId,
154→        wallId: segment.wallId,
155→      }
156→    ))
157→  ));
158→}
