160→function buildSlabObjects(floor) {
161→  return (floor.slabs || [])
162→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
163→    .map(slab => createPrismDescriptor(
164→      slab.id,
165→      'slab',
166→      slab.boundaryPoints,
167→      getSlabBottomLevel(slab),
168→      slab.thickness ?? 0,
169→      {
170→        sourceId: slab.id,
171→        floorId: floor.id,
172→      }
173→    ));
174→}
175→
176→function buildColumnObjects(floor, floorLevel) {
177→  return (floor.columns || []).map((column) => createBoxDescriptor(
178→    column.id,
179→    'column',
180→    { x: column.x, y: column.y },
181→    {
182→      x: column.width,
183→      y: column.height,
184→      z: column.depth,
185→    },
186→    floorLevel,
187→    (column.rotation || 0) * Math.PI / 180,
188→    {
189→      sourceId: column.id,
190→      floorId: floor.id,
191→    }
192→  ));
193→}
194→
195→function buildBeamObjects(floor) {
196→  return (floor.beams || [])
197→    .map((beam) => {
198→      const renderData = getBeamRenderData(beam, floor.columns || []);
199→      if (!renderData) return null;
200→
201→      return createLinearBoxDescriptor(
202→        beam.id,
203→        'beam',
204→        renderData.start,
205→        renderData.end,
206→        beam.width,
207→        beam.floorLevel - beam.depth,
208→        beam.depth,
209→        {
210→          sourceId: beam.id,
211→          floorId: floor.id,
212→        }
213→      );
214→    })
215→    .filter(Boolean);
216→}
