24→function createFallbackBounds(activeFloor) {
25→  const level = getFloorElevation(activeFloor);
26→  return {
27→    minX: -1500,
28→    maxX: 1500,
29→    minY: -1500,
30→    maxY: 1500,
31→    minElevation: level,
32→    maxElevation: level + 3000,
33→  };
34→}
