36→export function buildPreviewScene(project, options = {}) {
37→  const floors = getOrderedFloors(project);
38→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
39→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
40→  const visibleFloorIds = new Set(options.visibleFloorIds || (activeFloorId ? [activeFloorId] : []));
41→
42→  const floorDescriptors = floors.map((floor) => {
43→    const objects = buildFloorPreviewObjects(floor);
44→    return {
45→      floorId: floor.id,
46→      name: floor.name,
47→      elevation: getFloorElevation(floor),
48→      visible: visibleFloorIds.has(floor.id),
49→      objects,
50→      bounds: boundsFromObjects(objects),
51→    };
52→  });
53→
54→  const visibleObjects = floorDescriptors
55→    .filter((floor) => floor.visible)
56→    .flatMap((floor) => floor.objects);
57→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(activeFloor);
58→
59→  return {
60→    activeFloorId,
61→    visibleFloorIds: [...visibleFloorIds],
62→    floors: floorDescriptors,
63→    bounds,
64→    defaultTarget: {
65→      x: (bounds.minX + bounds.maxX) / 2,
66→      y: (bounds.minElevation + bounds.maxElevation) / 2,
67→      z: (bounds.minY + bounds.maxY) / 2,
68→    },
69→    groundLevel: getFloorElevation(activeFloor),
70→    hasVisibleObjects: visibleObjects.length > 0,
71→  };
72→}
